/**
 * 科レベルの形態特性データ（検索表フィルタ用）
 * 各配列は「その科内で見られるパターン」。
 * 例: バラ科 habit: ["tree","shrub","herb"] → 高木・低木・草本いずれもある
 *
 * データソース: Watson & Dallwitz "The Families of Flowering Plants" (DELTA)
 * 補足: 裸子植物・一部APG新設科は手動
 */
import type {
  LeafArr, LeafType, CompoundType, Venation, VenationNet,
  Margin, LeafShape, Dissection, Stipules, Habit, LeafLongevity,
  Latex, Aromatic, GlandDotted, StemSection,
  FlowerSymmetry, PetalCount, PetalFusion, OvaryPosition, StamenCount, PlantSex,
} from "./types";

export interface FamilyTraits {
  // ── 葉・茎（通年観察可能） ──
  leafArr: LeafArr[];
  leafType: LeafType[];
  compoundType?: CompoundType[];
  venation: Venation[];
  venationNet?: VenationNet[];
  margin: Margin[];
  shape?: LeafShape[];
  dissection?: Dissection[];
  stipules?: Stipules[];
  habit: Habit[];
  deciduous: LeafLongevity[];
  latex?: Latex[];
  aromatic?: Aromatic[];
  glandDotted?: GlandDotted[];
  stemSection?: StemSection[];
  // ── 花・果実（開花期に観察） ──
  flowerSymmetry?: FlowerSymmetry[];
  petalCount?: PetalCount[];
  petalFusion?: PetalFusion[];
  ovaryPosition?: OvaryPosition[];
  stamenCount?: StamenCount[];
  plantSex?: PlantSex[];
}

