// ── 共通パターンの略記用ヘルパー ──────────────────────────────
const D = (o: Partial<FamilyTraits>): FamilyTraits => ({
  leafArr: o.leafArr ?? ["alt"],
  leafType: o.leafType ?? ["simple"],
  venation: o.venation ?? ["pinnate"],
  margin: o.margin ?? ["entire"],
  shape: o.shape,
  habit: o.habit ?? ["herb"],
  deciduous: o.deciduous ?? ["deciduous"],
  compoundType: o.compoundType,
  venationNet: o.venationNet,
  dissection: o.dissection,
  stipules: o.stipules,
  latex: o.latex,
  aromatic: o.aromatic,
  glandDotted: o.glandDotted,
  stemSection: o.stemSection,
  flowerSymmetry: o.flowerSymmetry,
  petalCount: o.petalCount,
  petalFusion: o.petalFusion,
  ovaryPosition: o.ovaryPosition,
  stamenCount: o.stamenCount,
  plantSex: o.plantSex,
});

